import{_ as t,o,c as a,a2 as c}from"./chunks/framework.Crpw6aS5.js";const h=JSON.parse('{"title":"人才管理","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-scene/人才管理.md","filePath":"05_quotes/by-scene/人才管理.md"}'),r={name:"05_quotes/by-scene/人才管理.md"};function u(n,e,l,s,q,_){return o(),a("div",null,[...e[0]||(e[0]=[c('<h1 id="人才管理" tabindex="-1">人才管理 <a class="header-anchor" href="#人才管理" aria-label="Permalink to &quot;人才管理&quot;">​</a></h1><blockquote><p>&quot;要找比你更聪明、更有品格的人，然后充分授权，不要干涉。记住，品格比能力更重要。&quot;——巴菲特</p></blockquote><hr><h2 id="核心金句" tabindex="-1">核心金句 <a class="header-anchor" href="#核心金句" aria-label="Permalink to &quot;核心金句&quot;">​</a></h2><blockquote><p>&quot;我们选择经理人有三个标准：智慧、精力和品格。如果缺少第三个，前两个会把人毁掉。&quot;</p></blockquote><blockquote><p>&quot;我对运营几乎没什么事做。公平说，如果我们没有菲尔·利切（GEICO管理者），我们做成这样，更少做成更少。&quot;</p></blockquote><blockquote><p>&quot;B夫人用一句话概括了她的管理哲学：&#39;降价销售，用更低的价格卖更多的货。&#39;这种简单直接正是卓越管理者的标志。&quot;</p></blockquote><blockquote><p>&quot;我们对经理人不设绩效考核。我们相信优秀的人不需要外部压力，糟糕的人不会被绩效考核改变。&quot;</p></blockquote><blockquote><p>&quot;激励必须与结果挂钩，性质简单，可以轻松衡量，与参与者日常活动直接相关。&quot;</p></blockquote><hr><h2 id="相关主题" tabindex="-1">相关主题 <a class="header-anchor" href="#相关主题" aria-label="Permalink to &quot;相关主题&quot;">​</a></h2><p><a href="/02_concepts/management.html">管理层</a> · <a href="/02_concepts/reputation.html">声誉</a> · <a href="/02_concepts/executive-compensation.html">高管薪酬</a> · <a href="/02_concepts/contrarian.html">逆向思维</a></p>',12)])])}const i=t(r,[["render",u]]);export{h as __pageData,i as default};
